// ExecuteAgentAction is the resolver for the executeAgentAction field.
func (r *mutationResolver) ExecuteAgentAction(ctx context.Context, beanID string, actionID string) (bool, error) {
	if r.AgentMgr == nil {
		return false, fmt.Errorf("agent manager not available")
	}

	action := findAgentAction(actionID)
	if action == nil {
		return false, fmt.Errorf("unknown agent action: %s", actionID)
	}

	var workDir string
	if beanID == CentralSessionID {
		workDir = r.ProjectRoot
	} else {
		var err error
		workDir, err = r.findWorktreePath(beanID)
		if err != nil {
			return false, err
		}
	}

	actCtx := actionContext{WorktreeID: beanID, WorkDir: workDir, MainRepoPath: r.ProjectRoot}

	// Populate git state
	actCtx.HasChanges = gitutil.HasChanges(workDir)
	if r.WorktreeMgr != nil {
		actCtx.HasNewCommits = gitutil.HasUnmergedCommits(workDir, r.WorktreeMgr.BaseRef())
		actCtx.HasUnpushedCommits = gitutil.HasUnpushedCommits(workDir)
	}

	// Populate forge/PR state
	if r.Forge != nil {
		actCtx.ForgeCLI = r.Forge.CLIName()
		if branch, ok := gitutil.CurrentBranch(workDir); ok {
			pr, _ := r.Forge.FindPR(ctx, r.ProjectRoot, branch)
			actCtx.PullRequest = pr
		}
	}

	if err := r.AgentMgr.SendMessage(beanID, workDir, action.PromptFunc(actCtx), nil); err != nil {
		return false, err
	}
	return true, nil
}

// DiscardFileChange is the resolver for the discardFileChange field.
func (r *mutationResolver) DiscardFileChange(ctx context.Context, filePath string, staged bool, path *string) (bool, error) {
	dir := r.ProjectRoot
	if path != nil && *path != "" {
		if r.WorktreeMgr != nil {
			wts, err := r.WorktreeMgr.List()
			if err != nil {
				return false, err
			}
			valid := false
			for _, wt := range wts {
				if wt.Path == *path {
					valid = true
					break
				}
			}
			if !valid {
				return false, fmt.Errorf("unknown worktree path: %s", *path)
			}
		}
		dir = *path
	}

	if err := gitutil.DiscardFileChange(dir, filePath, staged); err != nil {
		return false, err
	}
	return true, nil
}

// OpenInEditor is the resolver for the openInEditor field.
func (r *mutationResolver) OpenInEditor(ctx context.Context, workspaceID string) (bool, error) {
	var dir string
	if workspaceID == CentralSessionID {
		dir = r.ProjectRoot
	} else {
		if r.WorktreeMgr == nil {
			return false, fmt.Errorf("worktree support not available")
		}
		wts, err := r.WorktreeMgr.List()
		if err != nil {
			return false, err
		}
		for _, wt := range wts {
			if wt.ID == workspaceID {
				dir = wt.Path
				break
			}
		}
		if dir == "" {
			return false, fmt.Errorf("worktree not found: %s", workspaceID)
		}
	}

	cmd := exec.Command("code", dir)
	if err := cmd.Start(); err != nil {
		return false, fmt.Errorf("failed to open editor: %w", err)
	}
	// Don't wait for the process — VS Code detaches itself
	go cmd.Wait()

	return true, nil
}

